import shioaji as _sj

_EXPORTS = {
    "Account": "Account",
    "AccountType": "AccountType",
    "StockAccount": "Account",
    "FutureAccount": "Account",
}

def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.account.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.account' has no attribute {name!r}")
